 1→import { NativeStackScreenProps } from '@react-navigation/native-stack';
 2→import {
 3→  PropsIconsNameCore,
 4→  PropsTokenColorsCore,
 5→} from '@semparar/design-system-app';
 6→import { TextIconType } from '@semparar/design-system-app/src/atomic/molecules/TextIcon/Models';
 7→import { PropsFintechCardRoutes } from '../../../routes/Models';
 8→
 9→export interface InvoiceCashbackViewProps {
10→  items: CashbackInvoiceItem[];
11→  hasError: boolean;
12→  hasLoading: boolean;
13→  handleGoBack: () => void;
14→  handleContinue: () => void;
15→  handleRetry: () => void;
16→  cashbackInvoiceList?: CashbackInvoiceItem[];
17→  isLoadingParameterization?: boolean;
18→  width: number;
19→}
20→
21→export interface InvoiceCashbackProps extends NativeStackScreenProps<
22→  PropsFintechCardRoutes,
23→  'InvoiceCashbackOnboarding'
24→> {}
25→
26→export interface CashbackInvoiceItem {
27→  text?: string;
28→  type: TextIconType;
29→  icon: PropsIconsNameCore;
30→  iconColor: PropsTokenColorsCore;
31→  iconColorShape: PropsTokenColorsCore;
32→  description: string;
33→}
34→

  1→import {
  2→  NavigationProp,
  3→  useFocusEffect,
  4→  useNavigation,
  5→} from '@react-navigation/native';
  6→import React, { FC, useCallback, useEffect, useRef, useState } from 'react';
  7→import { Dimensions } from 'react-native';
  8→
  9→import { usePoints } from '../../services';
 10→
 11→import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
 12→import ApiError from '../../atomic/organisms/ApiError';
 13→import BasicScreen from '../../atomic/templates/BasicScreen';
 14→import { PropsRootStack } from '../../routes/Models';
 15→import { CashbackInvoiceItem, InvoiceCashbackProps } from './models';
 16→import InvoiceCashbackView from './view';
 17→
 18→const InvoiceCashbackOnboarding: FC<InvoiceCashbackProps> = ({ route }) => {
 19→  const { width } = Dimensions.get('window');
 20→
 21→  const {
 22→    pointsQuantity,
 23→    isLoadingBalance,
 24→    isLoadingParameterization,
 25→    isErrorBalance,
 26→    isErrorParameterization,
 27→    requestParameterization,
 28→    requestPointsProducts,
 29→  } = usePoints();
 30→
 31→  const [refresh] = useState(0);
 32→  const hasFocused = useRef(false);
 33→  useFocusEffect(
 34→    React.useCallback(() => {
 35→      if (!hasFocused.current) {
 36→        eventScreenViewV3(
 37→          'desconto_fatura_onboarding',
 38→          'hub_recompensas_spmais',
 39→          'monetizacao',
 40→          {
 41→            location_1: 'monetizacao',
 42→            location_2: 'hub_recompensas_spmais',
 43→            location_3: 'desconto_fatura_onboarding',
 44→          },
 45→        );
 46→        hasFocused.current = true;
 47→      }
 48→      return () => {
 49→        hasFocused.current = false;
 50→      };
 51→    }, []),
 52→  );
 53→
 54→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
 55→
 56→  const conversionFactor = route?.params?.conversionFactor ?? 0;
 57→  const campaingId = route?.params?.campaingId ?? '';
 58→  const productCode = route?.params?.productCode ?? '';
 59→
 60→  const pointsQuantityValue = pointsQuantity || 0;
 61→
 62→  const handleGoBack = () => {
 63→    navigation.goBack();
 64→  };
 65→
 66→  const requestAll = useCallback(() => {
 67→    requestParameterization();
 68→    requestPointsProducts();
 69→  }, [
 70→    requestParameterization,
 71→    requestPointsProducts,
 72→  ]);
 73→
 74→  const handleRetry = () => {
 75→    if (isErrorParameterization) {
 76→      requestAll();
 77→    }
 78→  };
 79→
 80→  const handleContinue = () => {
 81→    navigation.navigate('InvoiceCashbackPoints', {
 82→      conversionFactor: conversionFactor,
 83→      campaingId: campaingId,
 84→      productCode: productCode,
 85→    });
 86→
 87→    eventSelectContent({
 88→      content_type: 'cta',
 89→      content_id: 'continuar',
 90→      location_1: 'monetizacao',
 91→      location_2: 'hub_recompensas_spmais',
 92→      location_3: 'desconto_fatura_onboarding',
 93→    });
 94→  };
 95→
 96→  const invoiceList = (): CashbackInvoiceItem[] => {
 97→    const finalPrice = pointsQuantityValue * conversionFactor;
 98→    const formattedPrice = new Intl.NumberFormat('pt-BR', {
 99→      style: 'currency',
100→      currency: 'BRL',
101→    }).format(finalPrice);
102→
103→    return [
104→      {
105→        type: 'default',
106→        icon: 'icon-switch-vertical',
107→        iconColor: 'BRAND_BASE_01',
108→        iconColorShape: 'INTENSE_COLOR_01',
109→        description: `Cada ${pointsQuantityValue} pontos valem ${formattedPrice} no cashback`,
110→      },
111→      {
112→        type: 'default',
113→        icon: 'icon-calendar',
114→        iconColor: 'BRAND_BASE_01',
115→        iconColorShape: 'INTENSE_COLOR_01',
116→        description:
117→          'Você define quanto cashback quer aplicar na sua fatura aberta',
118→      },
119→      {
120→        type: 'default',
121→        icon: 'icon-payment-invoice',
122→        iconColor: 'BRAND_BASE_01',
123→        iconColorShape: 'INTENSE_COLOR_01',
124→        description:
125→          'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
126→      },
127→      {
128→        type: 'default',
129→        icon: 'icon-clock',
130→        iconColor: 'BRAND_BASE_01',
131→        iconColorShape: 'INTENSE_COLOR_01',
132→        description: 'O cashback acontece em até 72h',
133→      },
134→    ];
135→  };
136→
137→  const items: CashbackInvoiceItem[] = invoiceList();
138→
139→  useEffect(() => {
140→    requestParameterization();
141→  }, [
142→    requestParameterization,
143→    refresh,
144→  ]);
145→
146→  if (isErrorParameterization) {
147→    return (
148→      <BasicScreen
149→        leftIconOnPress={handleGoBack}
150→        title="Cashback na fatura"
151→        errorButtonOnPress={handleRetry}
152→      >
153→        <ApiError onPress={handleRetry} />
154→      </BasicScreen>
155→    );
156→  }
157→  return (
158→    <InvoiceCashbackView
159→      handleGoBack={handleGoBack}
160→      handleContinue={handleContinue}
161→      handleRetry={handleRetry}
162→      items={items}
163→      hasError={isErrorBalance}
164→      hasLoading={isLoadingBalance}
165→      cashbackInvoiceList={invoiceList()}
166→      width={width}
167→      isLoadingParameterization={isLoadingParameterization}
168→    />
169→  );
170→};
171→
172→export default InvoiceCashbackOnboarding;
173→

